scwin.f_FieldClear = function () {
  $c.gus.cfInitObjects($p, tb_retrieve, null);
  cnd_lc_iogb.focus();
};

//-------------------------------------------------------------------------
// function name : f_DefaultValue
// function desc : 화면 open시 초기  데이타 setting
//-------------------------------------------------------------------------
scwin.f_DefaultValue = function () {
  cnd_lc_iogb.setValue(scwin.iogb);
  if (cnd_lc_iogb.getValue() == "I") {
    //Import
    io_gb.setValue("Arrival Date:");
  } else {
    io_gb.setValue("Onboard Date:");
  }
  cnd_ica_ondtFrom.setValue(scwin.strPreDate);
  cnd_ica_ondtTo.setValue(scwin.vCurDate);
};

//-------------------------------------------------------------------------
// 날짜설정
//-------------------------------------------------------------------------
scwin.f_SetDate = function (pSetType, pDayCnt) {
  //유형 1:현재일, 2:이전일, 3:이후일

  var vReturnDate = "";
  if (pSetType == "1") {
    //vReturnDate = new Date().format("YYYYMMDD");
    vReturnDate = scwin.vCurDate;
  } else if (pSetType == "2") {
    //vReturnDate = new Date().before(0, 0, pDayCnt).format("YYYYMMDD");
    vReturnDate = WebSquare.date.dateAdd(scwin.vCurDate, -1);
  } else if (pSetType == "3") {
    //vReturnDate = new Date().after(0, 0, pDayCnt).format("YYYYMMDD");
    vReturnDate = WebSquare.date.dateAdd(scwin.vCurDate, 1);
  }
  return vReturnDate;
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
  dma_search.set("kcomcd", scwin.hid_kcomcd); //대표거래처 코드

  if (cnd_ica_ondtFrom.getValue().trim() == '' || cnd_ica_ondtTo.getValue().trim() == '') {
    $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, Array("ETD"));
    cnd_ica_ondtFrom.focus();
    return false;
  }
  var chk = $c.gus.cfIsAfterDate($p, cnd_ica_ondtFrom.getValue(), cnd_ica_ondtTo.getValue());
  if (!chk) {
    $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
    cnd_ica_ondtFrom.focus();
    return false;
  }
  //tr_retrieve.post();
  $c.sbm.execute($p, sbm_retrieve);
};
scwin.f_CustemerBookingDetail = function () {
  //var condition = "?";
  var row = ds_CustomerBookingInfo.getRowPosition();
  var strExpertDetailUrl = "/ui/il/airout/aobk/ar_101_01_01b.xml";
  var strImportDetailUrl = "/ui/il/airinb/aibk/ar_201_01_01b.xml";
  if (row > -1) {
    //선택된 오더 정보 : 오더번호 / 화물구분
    var v_kmcom = ds_CustomerBookingInfo.getCellData(row, "kcomcd");
    var v_srno = ds_CustomerBookingInfo.getCellData(row, "srno");
    var param = {
      kcomcd: v_kmcom,
      srno: v_srno
    };

    //condition += "kcomcd=" + v_kmcom + "&srno=" + v_srno;
    if (cnd_lc_iogb.getValue() == "O") {
      //cfTabMenuUpdate(strExpertDetailUrl+condition,"Export Customer Booking");
      $c.win.openMenu($p, "Export Customer Booking", strExpertDetailUrl, "ar_101_01_01b.xml", param, {
        openAction: "exist"
      });
    } else {
      //cfTabMenuUpdate(strImportDetailUrl+condition,"Import Customer Booking");
      $c.win.openMenu($p, "Import Customer Booking", strImportDetailUrl, "ar_201_01_01b.xml", param, {
        openAction: "exist"
      });
    }
  } else {
    $c.win.alert($p, E_MSG_CM_ERR_056);
    //$c.win.alert("Nothing has been selected.");
    return;
  }
};

